-func TestExportImport(t *testing.T) {
-	t.Parallel()
-	tmpDir := t.TempDir()
-	dbPath := filepath.Join(tmpDir, "test.db")
-	store := newTestStoreWithPrefix(t, dbPath, "test")
-
-	h := newExportImportHelper(t, store)
-	now := time.Now()
-
